  // Now simulate press-hold to show power/spin meter active, then screenshot.
  await page.mouse.down();
  await page.mouse.move(720, 320); // drag up for spin
  await page.waitForTimeout(300);
  await page.screenshot({path:"/tmp/bowl_power.png"});
  await page.mouse.up();
  await browser.close();server.close();
  console.log("shots saved");
})().catch(e=>{console.error(e);server.close();process.exit(2);});
